    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Use im2col with runtime dispatch: if col_size is divisible by 4, use
     *  nn_mat_mul_kernel_q7_bias_2sft_unroll4 (4-pixel batches with vd4dots);
     *  otherwise fall back to nn_mat_mul_kernel_q7_bias_2sft (2-pixel batches).
     */

    q7_t     *pBuffer = (q7_t*)in_tmp_buf;
    q7_t     *pOut = out_tensor;
    int bound_x_begin = (pad_x + stride_x - 1) / stride_x;
    int bound_x_end   = (in_tensor_dim_x + pad_x - ker_dim_x + stride_x) / stride_x;
    int bound_y_begin = (pad_y + stride_y - 1) / stride_y;
    int bound_y_end   = (in_tensor_dim_y + pad_y - ker_dim_y + stride_y) / stride_y;
    int col_size = in_tensor_ch * ker_dim_x * ker_dim_y;
    int use_unroll4 = (col_size % 4 == 0);
    int batch_size = use_unroll4 ? 4 : 2;

    /* Macro to flush the im2col buffer when full */
#define FLUSH_BUFFER()                                                          \
    if (pBuffer == (q7_t *)in_tmp_buf + batch_size * col_size)                  \
    {                                                                           \
        if (use_unroll4)                                                        \
            pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,           \
                        (q7_t*)in_tmp_buf, out_tensor_ch, col_size,             \
                        pre_rshift, out_scale, post_rshift, bias, pOut);        \
        else                                                                    \
            pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,                   \
                        (q7_t*)in_tmp_buf, out_tensor_ch, col_size,             \
                        pre_rshift, out_scale, post_rshift, bias, pOut);        \
        pBuffer = (q7_t *)in_tmp_buf;                                           \
    }

    /* top part */
    for (i_out_y = 0; i_out_y < bound_y_begin; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            FLUSH_BUFFER();
        }
    }

    /* middle part -- split x into left, mid, right */
    for (; i_out_y < bound_y_end; i_out_y++)
    {
        /* left part */
        for (i_out_x = 0; i_out_x < bound_x_begin; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            FLUSH_BUFFER();
        }

        /* mid part -- no padding, use bulk copy */
        for (; i_out_x < bound_x_end; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                nn_dup_s8
                ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim_x);
                pBuffer += in_tensor_ch * ker_dim_x;
            }

            FLUSH_BUFFER();
        }

        /* right part */
        for (; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            FLUSH_BUFFER();
        }
    }

    /* bottom part */
    for (; i_out_y < out_tensor_dim_y; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            FLUSH_BUFFER();
        }
    }

#undef FLUSH_BUFFER

    /* check if there are left-over pixels in the buffer */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        int leftover_bytes = pBuffer - (q7_t *)in_tmp_buf;

        /* drain 2 pixels if we were in unroll4 mode and have >= 2 columns left */
        if (use_unroll4 && leftover_bytes >= 2 * col_size)
        {
            pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
                                                  (q7_t*)in_tmp_buf,
                                                  out_tensor_ch,
                                                  col_size,
                                                  pre_rshift,
                                                  out_scale,
                                                  post_rshift,
                                                  bias,
                                                  pOut);
            leftover_bytes -= 2 * col_size;
        }

        /* handle 1 remaining pixel with scalar path */
        if (leftover_bytes > 0)
        {
            const q7_t *pA = ker_weight;
            q7_t *pB = pBuffer - col_size;
            int i;

            for (i = 0; i < out_tensor_ch; i++)
            {
                q31_t sum = bias[i];
                uint16_t colCnt = col_size;
                q7_t *pB_iter = pB;

                while (colCnt)
                {
                    sum += *pA++ * *pB_iter++;
                    colCnt--;
                }

                sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
            }
        }
    }

